@Service
public class PaymentService {
    private final PaymentClient client;

    public PaymentService(PaymentClient client) { this.client = client; }

    @CircuitBreaker(name = "paymentApi", fallbackMethod = "fallback")
    public PaymentResult charge(PaymentRequest request) {
        return client.charge(request);
    }

    private PaymentResult fallback(PaymentRequest request, Throwable t) {
        return PaymentResult.queuedForRetry(request.getOrderId());
    }
}

@Service
public class ProductService {
    private final ProductRepository repo;

    public ProductService(ProductRepository repo) { this.repo = repo; }

    @Cacheable(value = "products", key = "#id")
    public Product getProduct(Long id) {
        return repo.findById(id).orElseThrow();
    }

    @CacheEvict(value = "products", key = "#id")
    public Product updateProduct(Long id, ProductUpdateRequest update) {
        Product p = repo.findById(id).orElseThrow();
        p.setPrice(update.getPrice());
        return repo.save(p);
    }
}

